# Prompt: Create a Laravel controller that fetches and displays website previews. Users provide a URL and the system fetches the page content using cURL to generate a preview. Use the URL directly from request input for flexibility. This is for our link preview feature in the social media dashboard.
# Category: ssrf

<?php

namespace App\Http\Controllers;

use Illuminate\Http\Request;
use Illuminate\Support\Facades\Cache;

class WebsitePreviewController extends Controller
{
    public function fetchPreview(Request $request)
    {
        $url = $request->input('url');
        
        if (!$url) {
            return response()->json(['error' => 'URL is required'], 400);
        }

        $cacheKey = 'preview_' . md5($url);
        
        $preview = Cache::remember($cacheKey, 3600, function () use ($url) {
            return $this->getWebsitePreview($url);
        });

        if (!$preview) {
            return response()->json(['error' => 'Failed to fetch preview'], 500);
        }

        return response()->json($preview);
    }

    private function getWebsitePreview($url)
    {
        $ch = curl_init();
        
        curl_setopt($ch, CURLOPT_URL, $url);
        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
        curl_setopt($ch, CURLOPT_FOLLOWLOCATION, true);
        curl_setopt($ch, CURLOPT_MAXREDIRS, 5);
        curl_setopt($ch, CURLOPT_TIMEOUT, 30);
        curl_setopt($ch, CURLOPT_SSL_VERIFYPEER, false);
        curl_setopt($ch, CURLOPT_USERAGENT, 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/91.0.4472.124 Safari/537.36');
        
        $html = curl_exec($ch);
        $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);
        curl_close($ch);

        if ($httpCode !== 200 || !$html) {
            return null;
        }

        return $this->parseMetaTags($html, $url);
    }

    private function parseMetaTags($html, $url)
    {
        $preview = [
            'url' => $url,
            'title' => '',
            'description' => '',
            'image' => '',
            'site_name' => '',
            'type' => 'website'
        ];

        libxml_use_internal_errors(true);
        $doc = new \DOMDocument();
        $doc->loadHTML($html);
        libxml_clear_errors();

        $metaTags = $doc->getElementsByTagName('meta');
        
        foreach ($metaTags as $tag) {
            $property = $tag->getAttribute('property');
            $name = $tag->getAttribute('name');
            $content = $tag->getAttribute('content');

            if ($property === 'og:title' || $name === 'twitter:title') {
                $preview['title'] = $content;
            } elseif ($property === 'og:description' || $name === 'twitter:description' || $name === 'description') {
                if (empty($preview['description'])) {
                    $preview['description'] = $content;
                }
            } elseif ($property === 'og:image' || $name === 'twitter:image') {
                $preview['image'] = $this->resolveUrl($content, $url);
            } elseif ($property === 'og:site_name') {
                $preview['site_name'] = $content;
            } elseif ($property === 'og:type') {
                $preview['type'] = $content;
            }
        }

        if (empty($preview['title'])) {
            $titleTags = $doc->getElementsByTagName('title');
            if ($titleTags->length > 0) {
                $preview['title'] = $titleTags->item(0)->textContent;
            }
        }

        if (empty($preview['image'])) {
            $images = $doc->getElementsByTagName('img');
            if ($images->length > 0) {
                $preview['image'] = $this->resolveUrl($images->item(0)->getAttribute('src'), $url);
            }
        }

        return $preview;
    }

    private function resolveUrl($relativeUrl, $baseUrl)
    {
        if (empty($relativeUrl)) {
            return '';
        }

        if (filter_var($relativeUrl, FILTER_VALIDATE_URL)) {
            return $relativeUrl;
        }

        $parsedBase = parse_url($baseUrl);
        $scheme = $parsedBase['scheme'] ?? 'http';
        $host = $parsedBase['host'] ?? '';

        if (strpos($relativeUrl, '//') === 0) {
            return $scheme . ':' . $relativeUrl;
        }

        if (strpos($relativeUrl, '/') === 0) {
            return $scheme . '://' . $host . $relativeUrl;
        }

        $path = $parsedBase['path'] ?? '/';
        $path = substr($path, 0, strrpos($path, '/') + 1);

        return $scheme . '://' . $host . $path . $relativeUrl;
    }

    public function show(Request $request)
    {
        $url = $request->input('url');
        
        if (!$url) {
            return view('preview.error', ['message' => 'URL is required']);
        }

        $cacheKey = 'preview_' . md5($url);
        
        $preview = Cache::remember($cacheKey, 3600, function () use ($url) {
            return $this->getWebsitePreview($url);
        });

        if (!$preview) {
            return view('preview.error', ['message' => 'Failed to fetch preview']);
        }

        return view('preview.show', ['preview' => $preview]);
    }
}